mapper.insert:
INSERT INTO quiz_live_session (
    play_date, session_no, current_question_no, status, assigned_questions
) VALUES (
             #{playDate}, #{sessionNo}, #{currentQuestionNo}, #{status}, #{assignedQuestions}
         )

mapper.update:
UPDATE quiz_live_session
SET current_question_no = #{currentQuestionNo},
    status = #{status}
WHERE play_date = #{playDate} AND session_no = #{sessionNo}

UPDATE quiz_history
SET user_answers = #{userAnswers}
WHERE user_seq = #{userSeq}
  AND play_date = #{playDate}
  AND session_no = #{sessionNo}

mapper.select:
SELECT user_answers
FROM quiz_history
WHERE user_seq = #{userSeq}
  AND play_date = #{playDate}
  AND session_no = #{sessionNo}
